SELECT f.*
       FROM file f WHERE 1 = 1 AND f.del = #{del}  AND f.p_id = #{pId} 
            AND f.file_name = #{fileName} 
            AND f.file_path = #{filePath} 
            AND f.file_type = #{fileType} 
            AND f.is_file = #{isFile} 
            AND f.is_exist = #{isExist} 
            AND f.has_child = #{hasChild} 
            AND f.user_id = #{userId}  ORDER BY f.id
       DESC

SELECT f.*
       FROM file f WHERE 0 = 0 AND f.p_id = #{pId} AND f.del = #{del} AND f.is_file = #{isFile} AND
       f.is_exist = #{isExist} ORDER BY f.gmt_create DESC LIMIT #{currentPage}, #{pageSize}

SELECT f.*
       FROM file f WHERE 1 = 1  AND f.del = #{del} 
            AND f.p_id = #{pId} 
            AND f.file_name LIKE CONCAT('%',
       #{fileName}, '%') 
            AND f.file_path =
       #{filePath} 
            AND f.file_type =
       #{fileType} 
            AND f.is_file = #{isFile} 
            AND f.is_exist = #{isExist} 
            AND f.has_child = #{hasChild} 
            AND f.user_id = #{userId}  ORDER BY f.gmt_created DESC LIMIT
       #{offset}, #{pageSize}

SELECT count(*) FROM file f WHERE 1 = 1  AND f.del = #{del} 
        AND
       f.p_id = #{pId} 
        AND f.file_name LIKE
       CONCAT('%', #{fileName}, '%') 
        AND
       f.file_path = #{filePath} 
        AND
       f.file_type = #{fileType} 
        AND f.is_file =
       #{isFile} 
        AND f.is_exist = #{isExist} 
        AND f.has_child = #{hasChild} 
        AND f.user_id = #{userId}
